// Noncompliant: const reference parameters
cppcoro::task<void> processData(const std::string& data) {
    // The reference may become invalid if the caller
    // destroys the string before the coroutine completes
    co_await someAsyncOperation();
    std::cout << data << std::endl; // Potential dangling reference
}

cppcoro::generator<int> processVector(const std::vector<int>& vec) {
    for (const auto& item : vec) {
        co_await std::chrono::milliseconds(100);
        co_yield item; // vec may be destroyed
    }
}

compliant:
// Compliant: Pass by value
cppcoro::task<void> processData(std::string data) {
    // Safe: data is copied
    co_await someAsyncOperation();
    std::cout << data << std::endl;
}

// Compliant: Use string_view for read-only access
cppcoro::task<void> processDataView(std::string_view data) {
    // Process immediately, don't store reference
    logData(data);
    co_await someAsyncOperation();
}

// Compliant: Move semantics
cppcoro::task<void> processDataMove(std::string&& data) {
    std::string local_data = std::move(data);
    co_await someAsyncOperation();
    std::cout << local_data << std::endl;
}
